export default function InboundPage() {
  const { hasRole } = useAuth();
  const { selectedWarehouseId } = useWarehouse();
  const [data, setData] = useState([]);
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [modal, setModal] = useState({ open: false, mode: 'create', data: null });
  const [statusFilter, setStatusFilter] = useState('');

  const fetchData = () => {
    setLoading(true);
    const params = {};
    if (selectedWarehouseId) params.warehouse_id = selectedWarehouseId;
    if (statusFilter) params.status = statusFilter;
    inboundApi.getAll(params)
      .then(r => setData(r.data))
      .catch(() => toast.error('Lá»—i táº£i phiáº¿u nháº­p'))
      .finally(() => setLoading(false));
  };

  useEffect(() => { fetchData(); }, [selectedWarehouseId, statusFilter]);

  useEffect(() => {
    productApi.getAll({}).then(r => setProducts(r.data)).catch(() => {});
  }, []);

  const handleApprove = async (row) => {
    if (!confirm(`Duyá»‡t phiáº¿u ${row.inbound_code}?`)) return;
    try {
      await inboundApi.approve(row.id);
      toast.success('Duyá»‡t phiáº¿u thÃ nh cÃ´ng!');
      fetchData();
