function SalesForm({ selectedWarehouseId, onSave, onCancel }) {
  const [customerId, setCustomerId] = useState('');
  const [items, setItems] = useState([{ product_id: '', quantity: 1 }]);
  const [customers, setCustomers] = useState([]);
  const [products, setProducts] = useState([]);
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    customerApi.getAll({}).then(r => setCustomers(r.data)).catch(() => {});
    productApi.getAll({}).then(r => setProducts(r.data)).catch(() => {});
  }, []);

  const addItem = () => setItems([...items, { product_id: '', quantity: 1 }]);
  const removeItem = (i) => setItems(items.filter((_, idx) => idx !== i));
  const updateItem = (i, field, val) => {
    const updated = [...items];
    updated[i] = { ...updated[i], [field]: val };
    setItems(updated);
  };

  const totalAmount = items.reduce((sum, item) => {
    const p = products.find(pr => pr.id === parseInt(item.product_id, 10));
    return sum + (p ? parseFloat(p.price) * (item.quantity || 0) : 0);
  }, 0);

  const handleSubmit = async () => {
    if (!selectedWarehouseId) return toast.error('Vui lÃ²ng chá»n kho tá»« header.');
    const validItems = items.filter(i => i.product_id && i.quantity > 0);
    if (validItems.length === 0) return toast.error('Cáº§n Ã­t nháº¥t 1 sáº£n pháº©m.');
    setSaving(true);
    try {
      await salesApi.create({ warehouse_id: selectedWarehouseId, customer_id: customerId || null, items: validItems });
      toast.success('Táº¡o Ä‘Æ¡n hÃ ng thÃ nh cÃ´ng!');
      onSave();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Táº¡o tháº¥t báº¡i.');
    } finally { setSaving(false); }
  };

  return (




        KhÃ¡ch hÃ ng
         setCustomerId(e.target.value)}>
          -- Chá»n khÃ¡ch hÃ ng --
          {customers.map(c => {c.customer_code} - {c.name})}




        {items.map((item, i) => (




              Sáº£n pháº©m {i + 1}
               updateItem(i, 'product_id', e.target.value)}>
                -- Chá»n --
                {products.map(p => {p.sku} - {p.name} ({formatCurrency(parseFloat(p.price))}))}




              SL
               updateItem(i, 'quantity', parseInt(e.target.value, 10) || 1)} min="1" />



              {products.find(p => p.id === parseInt(item.product_id, 10))
                ? formatCurrency(parseFloat(products.find(p => p.id === parseInt(item.product_id, 10)).price) * item.quantity)
                : '-'}

            {items.length > 1 &&  removeItem(i)} className="p-2 text-red-500 hover:bg-red-50 rounded">}

